import { z } from "zod";

import { protectedProcedure } from "@/rpc/middleware";
import { listEvents } from "@/services/task-event-service";
import { addLink, removeLink } from "@/services/task-link-service";
import {
  archiveTask as archiveTaskService,
  createTask,
  getTask,
  getTaskStats,
  listTasks,
  updateTask,
} from "@/services/task-service";

const taskStatusSchema = z.enum(["todo", "in_progress", "done"]);

const createTaskSchema = z.object({
  assigneeId: z.string().min(1),
  deadline: z.string().optional(),
  description: z.string().optional(),
  startDate: z.string().optional(),
  status: taskStatusSchema.optional(),
  title: z.string().min(1),
});

const updateTaskSchema = z.object({
  archived: z.boolean().optional(),
  assigneeId: z.string().min(1).optional(),
  deadline: z.string().nullable().optional(),
  description: z.string().nullable().optional(),
  id: z.number().int().positive(),
  startDate: z.string().nullable().optional(),
  status: taskStatusSchema.optional(),
  title: z.string().min(1).optional(),
});

const listTasksSchema = z.object({
  archived: z.boolean().optional(),
  assigneeId: z.array(z.string()).optional(),
  cursor: z.string().optional(),
  deadlineFrom: z.string().optional(),
  deadlineTo: z.string().optional(),
  entityId: z.string().optional(),
  entityType: z.string().optional(),
  limit: z.number().int().min(1).max(100).optional(),
  search: z.string().optional(),
  sortBy: z.enum(["deadline", "title", "status", "createdAt"]).optional(),
  sortOrder: z.enum(["asc", "desc"]).optional(),
  status: z.array(taskStatusSchema).optional(),
});

const getTaskByIdSchema = z.object({
  id: z.number().int().positive(),
});

const archiveTaskSchema = z.object({
  id: z.number().int().positive(),
});

const listEventsSchema = z.object({
  cursor: z.string().optional(),
  limit: z.number().int().min(1).max(100).optional(),
  taskId: z.number().int().positive(),
});

const addLinkSchema = z.object({
  entityId: z.string().min(1),
  entityType: z.string().min(1),
  taskId: z.number().int().positive(),
});

const removeLinkSchema = z.object({
  linkId: z.number().int().positive(),
});

export const createReminderSchema = z.object({
  offsetMinutes: z.number().int().optional(),
  taskId: z.number().int().positive().optional(),
  triggerAt: z.string().min(1),
  userId: z.string().min(1),
});

export const archiveReminderSchema = z.object({
  id: z.number().int().positive(),
});

const taskStatsSchema = z.object({}).optional();

export const listRemindersSchema = z.object({
  standalone: z.boolean().optional(),
  taskId: z.number().int().positive().optional(),
  userId: z.string().optional(),
});

export const taskCreate = protectedProcedure
  .input(createTaskSchema)
  .handler(async ({ input, context }) => {
    const task = await createTask({
      ...input,
      createdBy: context.user.id,
      status: input.status ?? "todo",
    });
    return task;
  });

export const taskUpdate = protectedProcedure
  .input(updateTaskSchema)
  .handler(async ({ input, context }) => {
    const { id, ...updates } = input;
    const userId = context.user.id;
    const task = await updateTask(id, updates, userId);
    return task;
  });

export const taskArchive = protectedProcedure
  .input(archiveTaskSchema)
  .handler(async ({ input, context }) => {
    const userId = context.user.id;
    const task = await archiveTaskService(input.id, userId);
    return task;
  });

export const taskGetById = protectedProcedure
  .input(getTaskByIdSchema)
  .handler(async ({ input }) => {
    const task = await getTask(input.id);
    if (!task) throw new Error("Task not found");
    return task;
  });

export const taskList = protectedProcedure
  .input(listTasksSchema)
  .handler(async ({ input }) => {
    const result = await listTasks({
      cursor: input.cursor,
      filters: {
        archived: input.archived,
        assigneeId: input.assigneeId,
        deadlineFrom: input.deadlineFrom,
        deadlineTo: input.deadlineTo,
        entityId: input.entityId,
        entityType: input.entityType,
        search: input.search,
        status: input.status,
      },
      limit: input.limit,
      sortBy: input.sortBy,
      sortOrder: input.sortOrder,
    });
    return result;
  });

export const taskListEvents = protectedProcedure
  .input(listEventsSchema)
  .handler(async ({ input }) => {
    return listEvents(input.taskId, input.cursor, input.limit ?? 50);
  });

export const taskAddLink = protectedProcedure
  .input(addLinkSchema)
  .handler(async ({ input }) => {
    const link = await addLink(input.taskId, input.entityType, input.entityId);
    return link;
  });

export const taskRemoveLink = protectedProcedure
  .input(removeLinkSchema)
  .handler(async ({ input }) => {
    await removeLink(input.linkId);
    return { success: true };
  });

export const taskStats = protectedProcedure
  .input(taskStatsSchema)
  .handler(async () => {
    return getTaskStats();
  });

import { ORPCError } from "@orpc/server";
import { hashPassword } from "better-auth/crypto";
import { and, eq } from "drizzle-orm";
import { alias } from "drizzle-orm/pg-core";
import { z } from "zod";

import { memberFormSchema as createUserSchema } from "@/lib/form-schemas/auth";
import { listPredefinedRoles } from "@/lib/auth/access-control";
import { db } from "@/lib/db/server";
import { protectedProcedure } from "@/rpc/middleware";
import { account, session, user } from "@/schema";
import { validateNoCircularSupervisor } from "@/services/supervisor-hierarchy-service";

const updateUserSchema = z.object({
  banExpires: z
    .string()
    .datetime()
    .optional()
    .transform((v) => (v ? new Date(v) : null)),
  banned: z.boolean().optional(),
  banReason: z.string().optional(),
  email: z.string().email().optional(),
  name: z.string().optional(),
  permissions: z.record(z.string(), z.array(z.string())).optional(),
  role: z
    .enum(["admin", "bd", "rm", "sc", "tl", "caller", "qc", "custom"])
    .optional(),
  supervisorId: z.string().optional(),
  userId: z.string(),
});

const archiveUserSchema = z.object({
  userId: z.string(),
});

const resetPasswordSchema = z.object({
  newPassword: z.string().min(8),
  userId: z.string(),
});

export const createUser = protectedProcedure
  .meta({
    permission: {
      action: "manage-roles" as const,
      resource: "team_members" as const,
    },
  })
  .input(createUserSchema)
  .handler(async ({ context, input }) => {
    if (input.role === "custom") {
      if (!input.permissions || Object.keys(input.permissions).length === 0) {
        throw new ORPCError("BAD_REQUEST", {
          message: "permissions must be non-empty when role is 'custom'",
        });
      }
    }

    if (input.role !== "admin" && !input.supervisorId) {
      throw new ORPCError("BAD_REQUEST", {
        message: "Non-admin users must have a supervisor",
      });
    }

    if (input.role === "admin") {
      input.supervisorId = undefined;
    }

    const normalizedEmail = input.email.toLowerCase();

    const [existing] = await db
      .select({ id: user.id })
      .from(user)
      .where(eq(user.email, normalizedEmail));

    if (existing) {
      throw new ORPCError("CONFLICT", {
        message: "A user with this email already exists",
      });
    }

    const id = crypto.randomUUID();

    if (input.supervisorId) {
      const [supervisor] = await db
        .select({ id: user.id })
        .from(user)
        .where(eq(user.id, input.supervisorId));

      if (!supervisor) {
        throw new ORPCError("BAD_REQUEST", {
          message: "Supervisor not found",
        });
      }

      await validateNoCircularSupervisor(
        id,
        input.supervisorId,
        context.subordinateCache,
      );
    }

    await db.insert(user).values({
      email: normalizedEmail,
      id,
      name: input.name,
      permissions: input.role === "custom" ? input.permissions : null,
      role: input.role,
      supervisorId: input.supervisorId ?? null,
    });

    const hashedPassword = await hashPassword(input.password);
    await db.insert(account).values({
      accountId: id,
      id: crypto.randomUUID(),
      password: hashedPassword,
      providerId: "credential",
      userId: id,
    });

    return { id };
  });

export const updateUser = protectedProcedure
  .meta({
    permission: {
      action: "manage-roles" as const,
      resource: "team_members" as const,
    },
  })
  .input(updateUserSchema)
  .handler(async ({ context, input }) => {
    const {
      userId,
      role,
      permissions,
      banned,
      banReason,
      banExpires,
      name,
      email,
      supervisorId,
    } = input;

    if (role === "custom") {
      if (!permissions || Object.keys(permissions).length === 0) {
        throw new ORPCError("BAD_REQUEST", {
          message: "permissions must be non-empty when role is 'custom'",
        });
      }
    }

    const [existing] = await db
      .select({ role: user.role, supervisorId: user.supervisorId })
      .from(user)
      .where(eq(user.id, userId));

    if (!existing) {
      throw new ORPCError("NOT_FOUND", { message: "User not found" });
    }

    const effectiveRole = role ?? existing.role;
    const effectiveSupervisorId =
      supervisorId !== undefined ? supervisorId : existing.supervisorId;

    if (effectiveRole !== "admin" && !effectiveSupervisorId) {
      throw new ORPCError("BAD_REQUEST", {
        message: "Non-admin users must have a supervisor",
      });
    }

    if (supervisorId) {
      const [supervisor] = await db
        .select({ id: user.id })
        .from(user)
        .where(eq(user.id, supervisorId));

      if (!supervisor) {
        throw new ORPCError("BAD_REQUEST", {
          message: "Supervisor not found",
        });
      }

      await validateNoCircularSupervisor(
        userId,
        supervisorId,
        context.subordinateCache,
      );
    }

    const updateData: Partial<typeof user.$inferInsert> = {};

    if (role !== undefined) {
      updateData.role = role;
    }

    if (banned === true) {
      updateData.banned = true;
      updateData.banReason = banReason ?? null;
      updateData.banExpires = banExpires ?? null;
    } else if (banned === false) {
      updateData.banned = false;
      updateData.banReason = null;
      updateData.banExpires = null;
    }

    if (permissions !== undefined) {
      updateData.permissions =
        role === "custom" || (role === undefined && permissions)
          ? permissions
          : null;
    }
    if (name !== undefined) updateData.name = name;
    if (email !== undefined) updateData.email = email;

    if (supervisorId !== undefined) {
      updateData.supervisorId = supervisorId;
    }

    if (Object.keys(updateData).length > 0) {
      await db.update(user).set(updateData).where(eq(user.id, userId));
    }

    if (banned === true) {
      await db.delete(session).where(eq(session.userId, userId));
    }

    if (role !== undefined || permissions !== undefined) {
      await db.delete(session).where(eq(session.userId, userId));
    }

    return { success: true };
  });

export const listUsers = protectedProcedure
  .meta({
    permission: {
      action: "manage-roles" as const,
      resource: "team_members" as const,
    },
  })
  .handler(async () => {
    const supervisor = alias(user, "supervisor");

    const users = await db
      .select({
        banExpires: user.banExpires,
        banned: user.banned,
        banReason: user.banReason,
        createdAt: user.createdAt,
        email: user.email,
        id: user.id,
        image: user.image,
        name: user.name,
        permissions: user.permissions,
        phoneNumber: user.phoneNumber,
        role: user.role,
        supervisorId: user.supervisorId,
        supervisorName: supervisor.name,
      })
      .from(user)
      .leftJoin(supervisor, eq(user.supervisorId, supervisor.id));

    return users;
  });

export const archiveUser = protectedProcedure
  .meta({
    permission: {
      action: "archive" as const,
      resource: "team_members" as const,
    },
  })
  .input(archiveUserSchema)
  .handler(async ({ input }) => {
    await db
      .update(user)
      .set({ banned: true, banReason: "Archived by admin" })
      .where(eq(user.id, input.userId));
    return { success: true };
  });

export const listRoles = protectedProcedure
  .meta({
    permission: {
      action: "manage-roles" as const,
      resource: "team_members" as const,
    },
  })
  .handler(async () => {
    return listPredefinedRoles();
  });

export const resetPassword = protectedProcedure
  .meta({
    permission: {
      action: "manage-roles" as const,
      resource: "team_members" as const,
    },
  })
  .input(resetPasswordSchema)
  .handler(async ({ input }) => {
    const hashedPassword = await hashPassword(input.newPassword);
    await db
      .update(account)
      .set({ password: hashedPassword })
      .where(
        and(
          eq(account.userId, input.userId),
          eq(account.providerId, "credential"),
        ),
      );
    return { success: true };
  });

import { and, asc, desc, eq, ilike, inArray, sql } from "drizzle-orm";
